# Good agent use case: open-ended research assistant
# Input is natural language, tools are chosen dynamically,
# execution path depends on what is found.

from anthropic import Anthropic

client = Anthropic()

TOOLS = [
    {
        'name': 'search_docs',
        'description': 'Search internal documentation',
        'input_schema': {
            'type': 'object',
            'properties': {'query': {'type': 'string'}},
            'required': ['query']
        }
    },
    {
        'name': 'read_file',
        'description': 'Read a source file by path',
        'input_schema': {
            'type': 'object',
            'properties': {'path': {'type': 'string'}},
            'required': ['path']
        }
    },
    {
        'name': 'run_test',
        'description': 'Run a specific test and return output',
        'input_schema': {
            'type': 'object',
            'properties': {'test_name': {'type': 'string'}},
            'required': ['test_name']
        }
    }
]

def research_agent(question: str) -> str:
    messages = [{'role': 'user', 'content': question}]
    while True:
        response = client.messages.create(
            model='claude-haiku-4-5-20251001',
            max_tokens=2048,
            tools=TOOLS,
            messages=messages
        )
        if response.stop_reason == 'end_turn':
            return response.content[0].text
        # handle tool calls dynamically — the agent decides what to look up
        tool_results = handle_tool_calls(response.content)
        messages.append({'role': 'assistant', 'content': response.content})
        messages.append({'role': 'user', 'content': tool_results})

def handle_tool_calls(content) -> list:
    results = []
    for block in content:
        if block.type == 'tool_use':
            result = dispatch_tool(block.name, block.input)
            results.append({
                'type': 'tool_result',
                'tool_use_id': block.id,
                'content': result
            })
    return results

def dispatch_tool(name: str, inputs: dict) -> str:
    if name == 'search_docs':
        return search_docs(inputs['query'])
    if name == 'read_file':
        return read_file(inputs['path'])
    if name == 'run_test':
        return run_test(inputs['test_name'])
    return 'Unknown tool'

# The agent is justified: user intent is unpredictable,
# tools needed depend on what the agent discovers.
answer = research_agent('Why does the payment module fail when the cart has zero items?')

# A simple evaluation harness to decide: rule engine or agent?
import time
from dataclasses import dataclass, field

@dataclass
class EvalResult:
    correct: int = 0
    total: int = 0
    total_ms: float = 0.0
    errors: list = field(default_factory=list)

    @property
    def accuracy(self) -> float:
        return self.correct / self.total if self.total else 0.0

    @property
    def avg_ms(self) -> float:
        return self.total_ms / self.total if self.total else 0.0

def evaluate(predictor, test_cases: list[tuple]) -> EvalResult:
    result = EvalResult()
    for inputs, expected in test_cases:
        t0 = time.perf_counter()
        try:
            predicted = predictor(*inputs)
            result.total_ms += (time.perf_counter() - t0) * 1000
            result.total += 1
            if predicted == expected:
                result.correct += 1
        except Exception as e:
            result.errors.append(str(e))
    return result

TEST_CASES = [
    (("App crashes on startup", ""), "bug"),
    (("How do I reset my password?", ""), "question"),
    (("Add dark mode support", ""), "feature"),
]

rule_result = evaluate(categorise_v2, TEST_CASES)
print(f"Rule engine: {rule_result.accuracy:.0%} accuracy, {rule_result.avg_ms:.1f}ms avg")
